-- 每个品类销量 Top 3
SELECT category, product, sales, rn FROM (
  SELECT category, product, sales,
    ROW_NUMBER() OVER (PARTITION BY category ORDER BY sales DESC) AS rn
  FROM products
) WHERE rn <= 3;

-- 用户活跃会话（10 分钟无活动则切分）
SELECT user_id, window_start, window_end, COUNT(*) AS events
FROM TABLE(
  SESSION(TABLE clicks, DESCRIPTOR(event_time), INTERVAL '10' MINUTE)
)
GROUP BY user_id, window_start, window_end;

-- 当日累计销售额（每小时输出一次）
SELECT window_start, window_end, SUM(amount) AS gmv
FROM TABLE(
  CUMULATE(TABLE orders, DESCRIPTOR(event_time), INTERVAL '1' HOUR, INTERVAL '1' DAY)
)
GROUP BY window_start, window_end;

-- 在表定义中声明处理时间属性
CREATE TABLE orders (
  order_id STRING,
  amount DECIMAL(10,2),
  proc_time AS PROCTIME()
) WITH ('connector' = 'kafka', ...);

-- 然后用作窗口时间列
SELECT window_start, COUNT(*)
FROM TABLE(TUMBLE(TABLE orders, DESCRIPTOR(proc_time), INTERVAL '1' MINUTE))
GROUP BY window_start;

CREATE TABLE clicks (
  user_id STRING,
  event_time TIMESTAMP(3),
  WATERMARK FOR event_time AS event_time - INTERVAL '5' SECOND
) WITH (...);
